import{_ as e,a,b as d}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as r,o as l,c as o,a2 as i}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"新增 Cloudflare R2 渠道","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/upload/cloudflare-r2.md","filePath":"zh-TW/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),n={name:"zh-TW/upload/cloudflare-r2.md"};function c(s,t,h,u,b,p){return l(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="新增-cloudflare-r2-渠道" tabindex="-1">新增 Cloudflare R2 渠道 <a class="header-anchor" href="#新增-cloudflare-r2-渠道" aria-label="Permalink to &quot;新增 Cloudflare R2 渠道&quot;">​</a></h1><h2 id="適合什麼情境" tabindex="-1">適合什麼情境 <a class="header-anchor" href="#適合什麼情境" aria-label="Permalink to &quot;適合什麼情境&quot;">​</a></h2><ul><li>你的 ImgBed 已經部署在 Cloudflare Pages 或 Workers 上。</li><li>你想把檔案直接存到同一個 Cloudflare 帳號底下的 R2 Bucket。</li><li>你希望檔案讀寫都走 Worker / Pages 的 R2 Binding，設定盡量單純。</li></ul><h2 id="新增前要準備什麼" tabindex="-1">新增前要準備什麼 <a class="header-anchor" href="#新增前要準備什麼" aria-label="Permalink to &quot;新增前要準備什麼&quot;">​</a></h2><table tabindex="0"><thead><tr><th>需要準備</th><th>用途</th></tr></thead><tbody><tr><td>Cloudflare 帳號</td><td>建立 R2 Bucket 與專案 Binding</td></tr><tr><td>一個 R2 Bucket</td><td>實際存放上傳檔案</td></tr><tr><td>目前部署 ImgBed 的 Pages / Worker 專案權限</td><td>把 Bucket 綁到執行環境</td></tr></tbody></table><p>R2 渠道不是在 ImgBed 後台手動新增。你需要先在 Cloudflare 把 R2 Bucket 綁到專案，Binding 變數名稱必須是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>img_r2</span></span></code></pre></div><h2 id="在-cloudflare-裡設定" tabindex="-1">在 Cloudflare 裡設定 <a class="header-anchor" href="#在-cloudflare-裡設定" aria-label="Permalink to &quot;在 Cloudflare 裡設定&quot;">​</a></h2><h3 id="第一步-建立-r2-bucket" tabindex="-1">第一步：建立 R2 Bucket <a class="header-anchor" href="#第一步-建立-r2-bucket" aria-label="Permalink to &quot;第一步：建立 R2 Bucket&quot;">​</a></h3><ol><li>登入 Cloudflare Dashboard。</li><li>進入 <code>R2 Object Storage</code>。</li><li>建立一個新的 Bucket。</li><li>Bucket 名稱可以自己取，例如 <code>imgbed</code>。</li></ol><p><img src="'+e+'" alt="建立 R2 Bucket" loading="lazy"></p><h3 id="第二步-把-bucket-綁到-imgbed-專案" tabindex="-1">第二步：把 Bucket 綁到 ImgBed 專案 <a class="header-anchor" href="#第二步-把-bucket-綁到-imgbed-專案" aria-label="Permalink to &quot;第二步：把 Bucket 綁到 ImgBed 專案&quot;">​</a></h3><p>依照你的部署方式找到 Binding 設定：</p><table tabindex="0"><thead><tr><th>部署方式</th><th>設定位置</th></tr></thead><tbody><tr><td>Pages</td><td>目前 Pages 專案 -&gt; Settings -&gt; Functions -&gt; R2 bucket bindings</td></tr><tr><td>Workers</td><td>目前 Worker 專案 -&gt; Settings -&gt; Bindings</td></tr></tbody></table><p>新增一筆 R2 Binding：</p><table tabindex="0"><thead><tr><th>欄位</th><th>填寫內容</th></tr></thead><tbody><tr><td>Variable name</td><td><code>img_r2</code></td></tr><tr><td>R2 bucket</td><td>選擇剛建立的 Bucket</td></tr></tbody></table><p>儲存 Binding 後，請重新部署一次 ImgBed，讓 Worker / Pages 執行環境真的拿到 <code>img_r2</code>。</p><h2 id="回到-imgbed-後台會看到什麼" tabindex="-1">回到 ImgBed 後台會看到什麼 <a class="header-anchor" href="#回到-imgbed-後台會看到什麼" aria-label="Permalink to &quot;回到 ImgBed 後台會看到什麼&quot;">​</a></h2><p>重新部署後，打開：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>系統設定 -&gt; 上傳設定</span></span></code></pre></div><p>如果 Binding 正確，會看到固定的 <code>Cloudflare R2</code> 渠道。這個渠道由系統自動建立，不需要你再新增一張渠道卡。</p><p>常見資訊如下：</p><table tabindex="0"><thead><tr><th>欄位</th><th>說明</th></tr></thead><tbody><tr><td>渠道名稱</td><td><code>Cloudflare R2</code></td></tr><tr><td>Binding 名稱</td><td><code>img_r2</code></td></tr><tr><td>啟用狀態</td><td>正常情況下可以直接啟用</td></tr></tbody></table><h2 id="容量限制" tabindex="-1">容量限制 <a class="header-anchor" href="#容量限制" aria-label="Permalink to &quot;容量限制&quot;">​</a></h2><p>如果你想讓 R2 參與容量控管，可以填 Cloudflare Account ID，並設定容量上限與提醒門檻。</p><p>Account ID 可以在 Cloudflare 帳號資訊區看到。只有需要查詢或限制 R2 用量時才需要填。</p><p><img src="'+a+'" alt="取得 Account ID" loading="lazy"></p><p><img src="'+d+'" alt="設定容量限制" loading="lazy"></p><h2 id="檢查方式" tabindex="-1">檢查方式 <a class="header-anchor" href="#檢查方式" aria-label="Permalink to &quot;檢查方式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>檢查項目</th><th>正常狀態</th></tr></thead><tbody><tr><td>後台是否出現渠道</td><td>上傳設定裡看得到 <code>Cloudflare R2</code></td></tr><tr><td>Binding 名稱</td><td>Cloudflare 裡的變數名稱是 <code>img_r2</code></td></tr><tr><td>是否重新部署</td><td>設定 Binding 後有重新部署 ImgBed</td></tr><tr><td>測試上傳</td><td>上傳圖片後，R2 Bucket 裡會出現檔案</td></tr></tbody></table><p>如果開啟檔案時出現 <code>R2 database binding is not configured</code>，通常代表執行環境沒有拿到 <code>img_r2</code> Binding。請檢查變數名稱，並重新部署專案。</p>',31)])])}const k=r(n,[["render",c]]);export{f as __pageData,k as default};
